const result = $input.first().json;

let resultado = '💰 Resumo Financeiro:\n';
resultado += `  Total cobrado: R$ ${parseFloat(result.total_cobrado || 0).toFixed(2)}\n`;
resultado += `  Total pago: R$ ${parseFloat(result.total_pago || 0).toFixed(2)}\n`;
resultado += `  Pendente: R$ ${parseFloat(result.total_pendente || 0).toFixed(2)}\n`;

if (parseFloat(result.total_atrasado) > 0) {
  resultado += `  ⚠️ Atrasado: R$ ${parseFloat(result.total_atrasado).toFixed(2)}\n`;
}

const proximos = result.proximos_vencimentos;
if (proximos && Array.isArray(proximos) && proximos.length > 0) {
  resultado += '\n📅 Próximos vencimentos:\n';
  for (const p of proximos) {
    resultado += `  • R$ ${parseFloat(p.valor).toFixed(2)} - ${new Date(p.vencimento).toLocaleDateString('pt-BR')} - ${p.descricao || ''}\n`;
  }
}

return [{ json: { resultado } }];
